prompt.task:
-- 改动: ChatBubble.tsx 在消息内容下方追加教学标签 --

在 `{tagStyle && (...)}` 标签块之前 (约第 66 行), 追加教学元数据显示:

// Phase 19-26: 教学标签 (仅教练消息)
{!isUser && (


    {/* AI 生成标记 */}
    {message.llm_generated && (

        AI

    )}
    {!message.llm_generated && message.actionType !== 'awakening' && (

        规则

    )}
    {/* 难度标记 */}
    {message.difficulty_contract?.level && (

        难度: {msgLevelLabel(message.difficulty_contract.level as string)}

    )}
    {/* 个性化标记 */}
    {message.personalization_evidence?.sources_count as number > 0 && (

        已引用历史

    )}

)}

新增辅助函数:

function msgLevelLabel(level: string): string {
  return { easy: '简单', medium: '中等', hard: '困难' }[level] || level;
}
